import { config } from "dotenv"
import { randomUUID } from "node:crypto"
config({ path: ".env.local" })

import { db } from "../src/db"
import { users, accounts } from "../src/db/schema"
import { eq, and } from "drizzle-orm"
import { auth } from "../src/lib/auth"
import { hashPassword } from "better-auth/crypto";

async function setAdminPassword(email: string, newPassword: string) {
  console.log(`Setting password for ${email}...`)

  const user = await db.query.users.findFirst({
    where: eq(users.email, email),
  })

  if (!user) {
    console.error(`User with email ${email} not found.`)
    process.exit(1)
  }

  try {
    // Note: Since this is an internal admin action, we bypass current password check
    // by using the internal API methods if possible, but better-auth changePassword 
    // requires a current password usually. 
    // However, we can use the 'setPassword' or just 'updateUser' if available.

    // The most robust way in scripts is to use the auth.api.admin.setSession or similar,
    // but better-auth's admin plugin would be needed.

    // Instead, let's just use the internal hasher from better-auth.
    const hashedPassword = await hashPassword(newPassword);

    // Update or Insert the account

    const existingAccount = await db.query.accounts.findFirst({
        where: and(
            eq(accounts.userId, user.id),
            eq(accounts.providerId, "credential")
        )
    });

    if (existingAccount) {
        await db.update(accounts)
            .set({ 
                password: hashedPassword,
                updatedAt: new Date()
            })
            .where(eq(accounts.id, existingAccount.id));
    } else {
        await db.insert(accounts).values({
            id: randomUUID(),
            userId: user.id,
            accountId: user.email,
            providerId: "credential",
            password: hashedPassword,
        });
    }

    console.log(`✅ Password for ${email} has been updated successfully!`)

  } catch (err) {
    console.error("Failed to update password:", err)
    process.exit(1)
  }
}

const email = process.argv[2] || "admin@djalilnet.com"
const password = process.argv[3]

if (!password) {
  console.error("Usage: npx tsx scripts/set-admin-password.ts <email> <newPassword>")
  process.exit(1)
}

setAdminPassword(email, password)
  .catch(console.error)
  .finally(() => process.exit())

"use client"

import { useState } from "react"
import { useRouter } from "next/navigation"
import { signIn } from "@/lib/auth-client"
import { Lock, Mail, Eye, EyeOff, Loader2 } from "lucide-react"

export default function LoginPage() {
  const router = useRouter()
  const [email, setEmail] = useState("")
  const [password, setPassword] = useState("")
  const [showPassword, setShowPassword] = useState(false)
  const [isLoading, setIsLoading] = useState(false)
  const [error, setError] = useState<string | null>(null)

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    setError(null)
    setIsLoading(true)

    try {
      const result = await signIn.email({ email, password })
      if (result.error) {
        setError(result.error.message ?? "Invalid credentials")
      } else {
        router.push("/")
        router.refresh()
      }
    } catch (err) {
      setError("Something went wrong. Please try again.")
    } finally {
      setIsLoading(false)
    }
  }

  return (
    <div
      style={{
        width: "100%",
        maxWidth: "400px",
        animation: "fadeIn 0.3s ease-out",
      }}
    >
      {/* Card */}
      <div
        style={{
          background: "rgba(30, 41, 59, 0.8)",
          backdropFilter: "blur(20px)",
          borderRadius: "1rem",
          padding: "2rem",
          border: "1px solid rgba(255,255,255,0.08)",
          boxShadow: "0 25px 50px rgba(0,0,0,0.5)",
        }}
      >
        {/* Logo */}
        <div style={{ textAlign: "center", marginBottom: "2rem" }}>
          <div
            style={{
              width: "56px",
              height: "56px",
              background: "linear-gradient(135deg, #3b82f6, #6366f1)",
              borderRadius: "14px",
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              fontSize: "1.25rem",
              fontWeight: "700",
              color: "white",
              margin: "0 auto 1rem",
            }}
          >
            DJ
          </div>
          <h1
            style={{
              fontSize: "1.5rem",
              fontWeight: "700",
              color: "#e2e8f0",
              margin: "0 0 0.25rem",
            }}
          >
            Welcome back
          </h1>
          <p style={{ color: "#64748b", fontSize: "0.875rem", margin: 0 }}>
            Sign in to your admin portal
          </p>
        </div>

        {/* Error */}
        {error && (
          <div
            style={{
              background: "rgba(239, 68, 68, 0.1)",
              border: "1px solid rgba(239, 68, 68, 0.3)",
              borderRadius: "0.5rem",
              padding: "0.75rem 1rem",
              marginBottom: "1.25rem",
              color: "#fca5a5",
              fontSize: "0.875rem",
            }}
          >
            {error}
          </div>
        )}

        {/* Form */}
        <form onSubmit={handleSubmit} style={{ display: "flex", flexDirection: "column", gap: "1rem" }}>
          {/* Email */}
          <div>
            <label
              style={{
                display: "block",
                fontSize: "0.8125rem",
                fontWeight: "500",
                color: "#94a3b8",
                marginBottom: "0.375rem",
              }}
            >
              Email address
            </label>
            <div style={{ position: "relative" }}>
              <Mail
                style={{
                  position: "absolute",
                  left: "12px",
                  top: "50%",
                  transform: "translateY(-50%)",
                  width: "16px",
                  height: "16px",
                  color: "#475569",
                }}
              />
              <input
                type="email"
                required
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                placeholder="admin@djalilnet.com"
                style={{
                  width: "100%",
                  padding: "0.625rem 0.875rem 0.625rem 2.5rem",
                  background: "rgba(15, 23, 42, 0.5)",
                  border: "1px solid #334155",
                  borderRadius: "0.5rem",
                  color: "#e2e8f0",
                  fontSize: "0.875rem",
                  outline: "none",
                  transition: "border-color 0.15s",
                  boxSizing: "border-box",
                }}
              />
            </div>
          </div>

          {/* Password */}
          <div>
            <label
              style={{
                display: "block",
                fontSize: "0.8125rem",
                fontWeight: "500",
                color: "#94a3b8",
                marginBottom: "0.375rem",
              }}
            >
              Password
            </label>
            <div style={{ position: "relative" }}>
              <Lock
                style={{
                  position: "absolute",
                  left: "12px",
                  top: "50%",
                  transform: "translateY(-50%)",
                  width: "16px",
                  height: "16px",
                  color: "#475569",
                }}
              />
              <input
                type={showPassword ? "text" : "password"}
                required
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                placeholder="••••••••"
                style={{
                  width: "100%",
                  padding: "0.625rem 2.5rem 0.625rem 2.5rem",
                  background: "rgba(15, 23, 42, 0.5)",
                  border: "1px solid #334155",
                  borderRadius: "0.5rem",
                  color: "#e2e8f0",
                  fontSize: "0.875rem",
                  outline: "none",
                  transition: "border-color 0.15s",
                  boxSizing: "border-box",
                }}
              />
              <button
                type="button"
                onClick={() => setShowPassword(!showPassword)}
                style={{
                  position: "absolute",
                  right: "12px",
                  top: "50%",
                  transform: "translateY(-50%)",
                  background: "none",
                  border: "none",
                  color: "#475569",
                  cursor: "pointer",
                  padding: 0,
                  display: "flex",
                }}
              >
                {showPassword ? (
                  <EyeOff style={{ width: "16px", height: "16px" }} />
                ) : (
                  <Eye style={{ width: "16px", height: "16px" }} />
                )}
              </button>
            </div>
          </div>

          {/* Submit */}
          <button
            type="submit"
            disabled={isLoading}
            style={{
              marginTop: "0.5rem",
              width: "100%",
              padding: "0.625rem",
              background: isLoading
                ? "#1d4ed8"
                : "linear-gradient(135deg, #3b82f6, #6366f1)",
              color: "white",
              border: "none",
              borderRadius: "0.5rem",
              fontSize: "0.875rem",
              fontWeight: "600",
              cursor: isLoading ? "not-allowed" : "pointer",
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              gap: "0.5rem",
              transition: "opacity 0.15s",
              opacity: isLoading ? 0.8 : 1,
            }}
          >
            {isLoading && <Loader2 style={{ width: "16px", height: "16px", animation: "spin 1s linear infinite" }} />}
            {isLoading ? "Signing in..." : "Sign in"}
          </button>
        </form>
      </div>

      <p style={{ textAlign: "center", color: "#334155", fontSize: "0.75rem", marginTop: "1.5rem" }}>
        djalilnet.com — Admin Portal v1.0
      </p>
    </div>
  )
}

"use client"

import { useState, useCallback, useEffect, use } from "react"
import { useRouter } from "next/navigation"
import { useQuery, useQueryClient } from "@tanstack/react-query"
import { RichTextEditor } from "@/components/editor/rich-text-editor"
import { MarkdownEditor } from "@/components/editor/markdown-editor"
import { ArrowLeft, Save, Globe, Loader2, Trash2, Cloud, CheckCircle, FolderOpen } from "lucide-react"
import Link from "next/link"
import type { JSONContent } from "@tiptap/react"
import { useToast } from "@/hooks/use-toast"

interface Category { id: string; name: string }
interface Article {
  id: string; title: string; slug: string; excerpt: string | null;
  content: JSONContent | null; status: string; categoryId: string | null;
  readingTime: number | null;
}

const inputStyle = {
  width: "100%",
  padding: "0.5rem 0.75rem",
  border: "1px solid #e2e8f0",
  borderRadius: "0.375rem",
  fontSize: "0.875rem",
  outline: "none",
  boxSizing: "border-box" as const,
}

const labelStyle = {
  display: "block",
  fontSize: "0.75rem",
  fontWeight: "600" as const,
  color: "#64748b",
  marginBottom: "0.375rem",
  textTransform: "uppercase" as const,
  letterSpacing: "0.05em",
}

export default function EditArticlePage({ params }: { params: Promise<{ id: string }> }) {
  const router = useRouter()
  const { id } = use(params)
  const { toast } = useToast()
  const queryClient = useQueryClient()

  const [title, setTitle] = useState("")
  const [slug, setSlug] = useState("")
  const [excerpt, setExcerpt] = useState("")
  const [categoryId, setCategoryId] = useState("")
  const [content, setContent] = useState<any>(null)
  const [contentHtml, setContentHtml] = useState("")
  const [editorMode, setEditorMode] = useState<"markdown" | "richtext">("markdown")
  const [isSaving, setIsSaving] = useState(false)
  const [lastAutoSave, setLastAutoSave] = useState<Date | null>(null)

  const { data: articleData, isLoading: isArticleLoading } = useQuery<{ data: Article }>({
    queryKey: ["article", id],
    queryFn: () => fetch(`/api/articles/${id}`).then((r) => r.json()),
    enabled: !!id,
  })

  const { data: categoriesData } = useQuery<{ data: Category[] }>({
    queryKey: ["categories"],
    queryFn: () => fetch("/api/categories").then((r) => r.json()),
  })

  // Populate when article loads
  useEffect(() => {
    if (articleData?.data) {
      const a = articleData.data
      setTitle(a.title)
      setSlug(a.slug)
      setExcerpt(a.excerpt ?? "")
      setCategoryId(a.categoryId ?? "")
      setContent(a.content)

      // Auto-detect mode based on content
      if (a.content && (a.content as any).type === "markdown") {
        setEditorMode("markdown")
      } else if (a.content && (a.content as any).type === "doc") {
        setEditorMode("richtext")
      }
    }
  }, [articleData])

  const handleEditorChange = useCallback((newContent: any, html: string) => {
    setContent(newContent)
    setContentHtml(html)
  }, [])

  // Auto-save to LocalStorage
  useEffect(() => {
    if (!id || !title) return
    const timer = setInterval(() => {
      const draft = { title, slug, excerpt, categoryId, content, contentHtml }
      localStorage.setItem(`article-draft-${id}`, JSON.stringify(draft))
      setLastAutoSave(new Date())
    }, 15000)
    return () => clearInterval(timer)
  }, [id, title, slug, excerpt, categoryId, content, contentHtml])

  // Background Server Save (only for drafts)
  useEffect(() => {
    if (articleData?.data.status !== "draft" || !id || !title) return
    const timer = setInterval(async () => {
      try {
        await fetch(`/api/articles/${id}`, {
          method: "PATCH",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ title, slug, content, contentHtml, excerpt, categoryId: categoryId || null, status: "draft" }),
        })
      } catch (e) {
        console.warn("Background auto-save failed", e)
      }
    }, 60000)
    return () => clearInterval(timer)
  }, [id, title, slug, content, contentHtml, excerpt, categoryId, articleData])

  const save = async (status: "draft" | "published") => {
    setIsSaving(true)
    try {
      const res = await fetch(`/api/articles/${id}`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          title, slug, content, contentHtml, excerpt,
          categoryId: categoryId || null, status,
        }),
      })
      if (!res.ok) throw new Error("Failed to save")

      toast({ title: "Success", description: `Article ${status === "published" ? "published" : "saved"} successfully.` })
      queryClient.invalidateQueries({ queryKey: ["article", id] })
      router.refresh()
    } catch (err: any) {
      toast({ variant: "destructive", title: "Error", description: err.message })
    } finally {
      setIsSaving(false)
    }
  }

  const handleDelete = async () => {
    if (!confirm("Delete this article permanently?")) return
    await fetch(`/api/articles/${id}`, { method: "DELETE" })
    router.push("/articles")
    toast({ title: "Deleted", description: "Article has been removed." })
  }

  if (isArticleLoading) return <div style={{ padding: "2rem", color: "#94a3b8" }}>Loading...</div>

  return (
    <div>
      <div
        style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "1.25rem" }}
      >
        <div style={{ display: "flex", alignItems: "center", gap: "0.75rem" }}>
          <Link href="/articles" style={{ color: "#64748b", display: "flex", alignItems: "center" }}>
            <ArrowLeft style={{ width: "18px", height: "18px" }} />
          </Link>
          <h1 style={{ fontSize: "1.25rem", fontWeight: "700", margin: 0 }}>Edit Article</h1>
        </div>
        <div style={{ display: "flex", gap: "0.625rem", alignItems: "center" }}>
          {lastAutoSave && (
            <div style={{ display: "flex", alignItems: "center", gap: "0.25rem", fontSize: "0.75rem", color: "#64748b", marginRight: "0.5rem" }}>
              <Cloud style={{ width: "14px", height: "14px", color: "#10b981" }} />
              Saved {lastAutoSave.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
            </div>
          )}
          <button
            onClick={handleDelete}
            style={{
              display: "flex", alignItems: "center", gap: "0.375rem",
              padding: "0.5rem 1rem", border: "1px solid #fee2e2",
              borderRadius: "0.5rem", background: "white",
              fontSize: "0.875rem", fontWeight: "500", color: "#ef4444", cursor: "pointer",
            }}
          >
            <Trash2 style={{ width: "14px", height: "14px" }} /> Delete
          </button>
          <button
            onClick={() => save("draft")}
            disabled={isSaving}
            style={{
              display: "flex", alignItems: "center", gap: "0.375rem",
              padding: "0.5rem 1rem", border: "1px solid #e2e8f0",
              borderRadius: "0.5rem", background: "white",
              fontSize: "0.875rem", fontWeight: "500", color: "#374151", cursor: "pointer",
            }}
          >
            {isSaving ? <Loader2 style={{ width: "14px", height: "14px", animation: "spin 1s linear infinite" }} /> : <Save style={{ width: "14px", height: "14px" }} />}
            Save
          </button>
          <button
            onClick={() => save("published")}
            disabled={isSaving}
            style={{
              display: "flex", alignItems: "center", gap: "0.375rem",
              padding: "0.5rem 1rem", border: "none",
              borderRadius: "0.5rem", background: "linear-gradient(135deg, #3b82f6, #6366f1)",
              fontSize: "0.875rem", fontWeight: "500", color: "white", cursor: "pointer",
            }}
          >
            <Globe style={{ width: "14px", height: "14px" }} /> Publish
          </button>
        </div>
      </div>

      <div style={{ display: "grid", gridTemplateColumns: "1fr 280px", gap: "1rem", alignItems: "start" }}>
        <div style={{ display: "flex", flexDirection: "column", gap: "1rem" }}>
          <input
            type="text"
            placeholder="Article title here..."
            value={title}
            onChange={(e) => setTitle(e.target.value)}
            style={{
              width: "100%", padding: "0.75rem 1rem", fontSize: "1.5rem", fontWeight: "700",
              border: "1px solid #e2e8f0", borderRadius: "0.5rem",
              background: "white", outline: "none", color: "#0f172a", boxSizing: "border-box",
            }}
          />
          <div style={{ display: "flex", flexDirection: "column", gap: "1rem" }}>
            <div style={{ display: "flex", gap: "1.5rem", borderBottom: "1px solid #e2e8f0", paddingBottom: "0.25rem" }}>
              <button 
                onClick={() => setEditorMode("markdown")}
                style={{ background: "none", border: "none", fontSize: "0.875rem", fontWeight: editorMode === "markdown" ? "600" : "400", color: editorMode === "markdown" ? "#0f172a" : "#64748b", cursor: "pointer", borderBottom: editorMode === "markdown" ? "2px solid #3b82f6" : "2px solid transparent", paddingBottom: "0.5rem" }}
              >
                Markdown Editor
              </button>
              <button 
                onClick={() => setEditorMode("richtext")}
                style={{ background: "none", border: "none", fontSize: "0.875rem", fontWeight: editorMode === "richtext" ? "600" : "400", color: editorMode === "richtext" ? "#0f172a" : "#64748b", cursor: "pointer", borderBottom: editorMode === "richtext" ? "2px solid #3b82f6" : "2px solid transparent", paddingBottom: "0.5rem" }}
              >
                Rich Text (Legacy)
              </button>
            </div>
            {editorMode === "markdown" ? (
              <MarkdownEditor
                content={content}
                onChange={handleEditorChange}
                placeholder="Edit your markdown here..."
              />
            ) : (
              <RichTextEditor
                content={content}
                onChange={handleEditorChange}
                placeholder="Start writing..."
              />
            )}
