            color: "white",
            borderRadius: "0.5rem",
            fontSize: "0.875rem",
            fontWeight: "500",
            textDecoration: "none",
          }}
        >
          <Plus style={{ width: "15px", height: "15px" }} />
          New Article
        </Link>
      </div>

      {/* Filters */}
      <div
        style={{
          background: "white",
          borderRadius: "0.75rem",
          border: "1px solid #e2e8f0",
          overflow: "hidden",
        }}
      >
        <div
          style={{
            padding: "0.875rem 1rem",
