                      </div>
                    </button>
                  )
                })}
              </div>
            )}
          </div>
        </div>

        {/* ===== EMAIL DETAIL PANEL ===== */}
        <div className={cn(
          "flex-1 flex flex-col min-w-0",
          // Mobile: hidden when showing list
          mobileView === "list" ? "hidden md:flex" : "flex"
        )}>
          {selectedEmail ? (
            <>
              {/* Detail Header */}
              <div className="p-4 sm:p-5 border-b border-slate-100 flex-shrink-0">
