                    padding: "0.875rem 1rem",
                    borderBottom: "1px solid #f8fafc",
                    borderLeft: selectedEmail?.id === email.id ? "3px solid #3b82f6" : "3px solid transparent",
                    background: selectedEmail?.id === email.id ? "#eff6ff" : "#fafafa",
                    border: "none",
                    cursor: "pointer",
