import type { JSONContent } from "@tiptap/react"

interface Template {
  id: string
  name: string
  subject: string
  bodyHtml: string
  variables: string[]
  createdAt: string
}

export default function TemplatesPage() {
  const queryClient = useQueryClient()
  const [showForm, setShowForm] = useState(false)
  const [editingId, setEditingId] = useState<string | null>(null)

  const [name, setName] = useState("")
  const [subject, setSubject] = useState("")
  const [bodyHtml, setBodyHtml] = useState("")
  const [isSaving, setIsSaving] = useState(false)
  const [viewMode, setViewMode] = useState<"edit" | "preview">("edit")

  const { data, isLoading } = useQuery<{ data: Template[] }>({
    queryKey: ["email-templates"],
    queryFn: () => fetch("/api/email/templates").then((r) => r.json()),
  })

  const extractVariables = (text: string) => {
    const matches = text.matchAll(/\{\{(.+?)\}\}/g)
    return Array.from(new Set(Array.from(matches).map(m => m[1].trim())))
  }

  const handleSave = async () => {
    setIsSaving(true)
    try {
      const variables = extractVariables(subject + bodyHtml)
      const url = editingId ? `/api/email/templates/${editingId}` : "/api/email/templates"
      const method = editingId ? "PATCH" : "POST"

      const res = await fetch(url, {
        method,
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ name, subject, bodyHtml, variables }),
      })

      if (!res.ok) throw new Error("Failed to save template")

      queryClient.invalidateQueries({ queryKey: ["email-templates"] })
      resetForm()
    } catch (err) {
      alert("Error saving template")
    } finally { setIsSaving(false) }
  }

  const handleDelete = async (id: string) => {
    if (!confirm("Are you sure you want to delete this template?")) return
    try {
      await fetch(`/api/email/templates/${id}`, { method: "DELETE" })
      queryClient.invalidateQueries({ queryKey: ["email-templates"] })
    } catch (err) {
      alert("Error deleting template")
    }
  }

  const resetForm = () => {
    setShowForm(false)
    setEditingId(null)
    setName(""); setSubject(""); setBodyHtml("")
    setViewMode("edit")
  }

  const startEdit = (template: Template) => {
    setEditingId(template.id)
    setName(template.name)
    setSubject(template.subject)
    setBodyHtml(template.bodyHtml)
    setShowForm(true)
  }

  const handleEditorChange = useCallback((_: JSONContent, html: string) => {
    setBodyHtml(html)
  }, [])

  return (
    <div className="p-6 max-w-7xl mx-auto space-y-8">
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-2xl font-bold text-slate-900 flex items-center gap-2">
            <Layout className="text-blue-600 w-6 h-6" />
            Email Templates
          </h1>
          <p className="text-slate-500 mt-1">Design beautiful, reusable email structures</p>
        </div>
        {!showForm && (
          <button
            onClick={() => setShowForm(true)}
            className="flex items-center gap-2 px-5 py-2.5 bg-blue-600 hover:bg-blue-700 text-white rounded-xl transition-all shadow-md shadow-blue-500/10 font-semibold"
          >
            <Plus className="w-5 h-5" />
            New Template
          </button>
        )}
      </div>

      {showForm && (
        <div className="bg-white border border-slate-200 rounded-2xl shadow-xl overflow-hidden animate-in fade-in slide-in-from-top-4 duration-300">
          <div className="p-5 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
            <div className="flex items-center gap-4">
               <h3 className="text-lg font-bold text-slate-800">
                {editingId ? "Edit Template" : "Create New Template"}
              </h3>
              <div className="flex bg-slate-200/60 p-1 rounded-lg">
                <button 
                  onClick={() => setViewMode("edit")}
                  className={`flex items-center gap-1.5 px-3 py-1 rounded-md text-xs font-bold transition-all ${viewMode === 'edit' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
                >
                  <Code className="w-3.5 h-3.5" /> EDITOR
                </button>
                <button 
                  onClick={() => setViewMode("preview")}
                  className={`flex items-center gap-1.5 px-3 py-1 rounded-md text-xs font-bold transition-all ${viewMode === 'preview' ? 'bg-white text-emerald-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
                >
                  <Eye className="w-3.5 h-3.5" /> PREVIEW
                </button>
              </div>
            </div>
            <button onClick={resetForm} className="text-slate-400 hover:text-slate-600 transition-colors">
              <X className="w-6 h-6" />
            </button>
          </div>

          <div className="p-6 space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-2">
                <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">Template Name</label>
                <input 
                  value={name} 
                  onChange={(e) => setName(e.target.value)} 
                  placeholder="e.g. Welcome Series - Day 1" 
                  className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 outline-none transition-all font-medium"
                />
              </div>
              <div className="space-y-2">
                <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">Default Subject Line</label>
                <input 
                  value={subject} 
                  onChange={(e) => setSubject(e.target.value)} 
                  placeholder="Subject (use {{name}} for dynamic data)" 
                  className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 outline-none transition-all font-medium"
                />
              </div>
            </div>

            <div className="space-y-2">
              <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">Email Body</label>
              {viewMode === "edit" ? (
                <div className="border border-slate-200 rounded-2xl overflow-hidden ring-1 ring-slate-100">
                  <RichTextEditor
                    content={bodyHtml || null}
                    onChange={handleEditorChange}
                    placeholder="Start designing your template content here..."
                    minHeight="450px"
                  />
                </div>
              ) : (
                <div className="border border-slate-200 rounded-2xl p-8 min-h-[450px] bg-slate-50 flex justify-center">
                  <div className="bg-white w-full max-w-2xl shadow-sm border border-slate-100 p-10 prose prose-slate">
                    <div className="mb-8 pb-4 border-b border-slate-100">
                      <p className="text-[10px] text-slate-400 uppercase font-bold tracking-widest mb-1">Subject Preview</p>
                      <h2 className="text-lg font-bold text-slate-800 m-0">{subject || "No subject set"}</h2>
                    </div>
                    <div dangerouslySetInnerHTML={{ __html: bodyHtml }} />
                  </div>
                </div>
              )}
              <div className="flex items-center gap-2 text-[10px] text-slate-400 font-bold p-2 px-4 bg-slate-50 rounded-lg border border-slate-100 mt-2">
                <Info className="w-3.5 h-3.5 text-blue-500" />
                TIP: VARIABLES WILL BE AUTOMATICALLY DETECTED BASED ON THE {"{{variable_name}}"} SYNTAX.
              </div>
            </div>

            <div className="flex gap-3 pt-2">
              <button
                onClick={handleSave}
                disabled={isSaving || !name || !subject || !bodyHtml}
                className="flex items-center gap-2 px-8 py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-xl disabled:opacity-50 font-bold transition-all shadow-lg shadow-blue-500/20"
              >
                {isSaving ? <Loader2 className="w-5 h-5 animate-spin" /> : <Save className="w-5 h-5" />}
                {editingId ? "Update Template" : "Save Template"}
              </button>
              <button
                onClick={resetForm}
                className="px-8 py-3 bg-slate-100 hover:bg-slate-200 text-slate-700 rounded-xl font-bold transition-all"
              >
                Cancel
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Templates list */}
      <div className="bg-white border border-slate-200 rounded-2xl overflow-hidden shadow-sm">
        {isLoading ? (
          <div className="p-20 text-center text-slate-400">
            <Loader2 className="w-10 h-10 animate-spin mx-auto mb-6 opacity-20" />
            <p className="font-medium">Loading your design library...</p>
          </div>
        ) : !data?.data || data.data.length === 0 ? (
          <div className="p-20 text-center text-slate-400">
            <FileText className="w-16 h-16 mx-auto mb-6 opacity-5" />
            <h3 className="text-slate-900 font-semibold mb-1 text-lg">Your template library is empty</h3>
            <p className="max-w-xs mx-auto text-sm">Templates allow you to reuse proven designs and save time on every campaign.</p>
            <button
              onClick={() => setShowForm(true)}
              className="mt-8 inline-flex items-center gap-2 px-6 py-2.5 bg-blue-600 text-white rounded-xl font-bold hover:bg-blue-700 transition-all shadow-md shadow-blue-500/10"
            >
              <Plus className="w-4 h-4" />
              Create Template
            </button>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-0 divide-x divide-y divide-slate-100">
            {data.data.map((template) => (
              <div key={template.id} className="p-6 hover:bg-slate-50/50 transition-all group relative">
                <div className="flex justify-between items-start mb-4">
                  <div className="p-2.5 bg-blue-50 text-blue-600 rounded-xl group-hover:bg-blue-600 group-hover:text-white transition-all">
                    <FileText className="w-6 h-6" />
                  </div>
                  <div className="flex gap-1.5 opacity-0 group-hover:opacity-100 transition-opacity">
                    <button
                      onClick={() => startEdit(template)}
                      className="p-2 bg-white border border-slate-200 rounded-lg text-slate-500 hover:text-blue-600 hover:border-blue-200 transition-all shadow-sm"
                      title="Edit Template"
                    >
                      <Pencil className="w-4 h-4" />
                    </button>
                    <button
                      onClick={() => handleDelete(template.id)}
                      className="p-2 bg-white border border-slate-200 rounded-lg text-slate-500 hover:text-rose-600 hover:border-rose-200 transition-all shadow-sm"
                      title="Delete Template"
                    >
                      <Trash2 className="w-4 h-4" />
                    </button>
                  </div>
                </div>

                <div className="space-y-2">
                  <h4 className="font-bold text-slate-900 truncate">{template.name}</h4>
                  <p className="text-xs text-slate-500 line-clamp-1 italic font-medium">"{template.subject}"</p>
                </div>

                <div className="mt-6 flex items-center justify-between">
                  <div className="flex flex-wrap gap-1">
                    {template.variables?.length > 0 ? (
                      template.variables.slice(0, 3).map((v) => (
                        <span key={v} className="px-1.5 py-0.5 bg-slate-100 text-[10px] font-bold text-slate-500 rounded uppercase tracking-tighter border border-slate-200/50">
                          {v}
                        </span>
                      ))
                    ) : (
                      <span className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Static Content</span>
                    )}
                    {template.variables?.length > 3 && (
                      <span className="text-[10px] text-slate-400 font-bold">+{template.variables.length - 3} more</span>
                    )}
                  </div>
                  <span className="text-[10px] text-slate-300 font-bold uppercase tracking-widest">
                    {formatRelativeTime(template.createdAt)}
                  </span>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  )
}

"use client"

import { useQuery, useQueryClient, useMutation } from "@tanstack/react-query"
import { 
  ImageIcon, 
  ExternalLink, 
  Copy, 
  Search, 
  Grid, 
  List,
  Upload,
  MoreVertical,
  Check,
  Folder,
  Plus,
  Trash2,
  FolderOpen,
  ChevronRight,
  MoreHorizontal
} from "lucide-react"
import { useState, useMemo } from "react"
import { UploadButton } from "@/lib/uploadthing"
import { useToast } from "@/hooks/use-toast"
import { 
  Dialog, 
  DialogContent, 
  DialogHeader, 
  DialogTitle, 
  DialogTrigger,
  DialogFooter
} from "@/components/ui/dialog"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"

interface MediaItem {
  url: string
  type: string
  title: string
  id: string
  albumId?: string | null
}

interface Album {
  id: string
  name: string
  description?: string
  mediaCount: number
}

export default function MediaPage() {
  const [searchTerm, setSearchTerm] = useState("")
  const [copiedUrl, setCopiedUrl] = useState<string | null>(null)
  const [selectedAlbumId, setSelectedAlbumId] = useState<string | null>(null)
  const [isCreateAlbumOpen, setIsCreateAlbumOpen] = useState(false)
  const [newAlbumName, setNewAlbumName] = useState("")
  const [isMoveDialogOpen, setIsMoveDialogOpen] = useState(false)
  const [movingItemId, setMovingItemId] = useState<string | null>(null)
  const [targetAlbumId, setTargetAlbumId] = useState<string>("none")

  const queryClient = useQueryClient()
  const { toast } = useToast()

  const { data: media, isLoading: isMediaLoading } = useQuery<MediaItem[]>({
    queryKey: ["media-items"],
    queryFn: async () => {
      const res = await fetch("/api/media")
      if (!res.ok) throw new Error("Failed to fetch media")
      return res.json()
    },
  })

  const { data: albums, isLoading: isAlbumsLoading } = useQuery<Album[]>({
    queryKey: ["media-albums"],
    queryFn: async () => {
      const res = await fetch("/api/media/albums")
      if (!res.ok) throw new Error("Failed to fetch albums")
      return res.json()
    },
  })

  // Mutations
  const deleteMutation = useMutation({
    mutationFn: async (id: string) => {
      const res = await fetch(`/api/media/${id}`, { method: "DELETE" })
      if (!res.ok) throw new Error("Failed to delete")
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["media-items"] })
      queryClient.invalidateQueries({ queryKey: ["media-albums"] })
      toast({ title: "Deleted", description: "Media item removed" })
    },
    onError: (err) => {
      toast({ variant: "destructive", title: "Error", description: err.message })
    }
  })

  const createAlbumMutation = useMutation({
    mutationFn: async (name: string) => {
      const res = await fetch("/api/media/albums", {
        method: "POST",
        body: JSON.stringify({ name }),
      })
      if (!res.ok) throw new Error("Failed to create album")
      return res.json()
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["media-albums"] })
      setIsCreateAlbumOpen(false)
      setNewAlbumName("")
      toast({ title: "Success", description: "Album created" })
    },
    onError: (err) => {
      toast({ variant: "destructive", title: "Error", description: err.message })
    }
  })

  const moveMutation = useMutation({
    mutationFn: async ({ id, albumId }: { id: string; albumId: string | null }) => {
      const res = await fetch(`/api/media/${id}`, {
        method: "PATCH",
        body: JSON.stringify({ albumId }),
      })
      if (!res.ok) throw new Error("Failed to move")
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["media-items"] })
      queryClient.invalidateQueries({ queryKey: ["media-albums"] })
      setIsMoveDialogOpen(false)
      setMovingItemId(null)
      toast({ title: "Updated", description: "Media moved successfully" })
    }
  })

  const filteredMedia = useMemo(() => {
    return media?.filter(item => {
      const matchesSearch = item.title?.toLowerCase().includes(searchTerm.toLowerCase()) ||
                            item.type?.toLowerCase().includes(searchTerm.toLowerCase())
      const matchesAlbum = selectedAlbumId === null || item.albumId === selectedAlbumId
      return matchesSearch && matchesAlbum
    })
  }, [media, searchTerm, selectedAlbumId])

  const currentAlbumName = selectedAlbumId 
    ? albums?.find(a => a.id === selectedAlbumId)?.name || "Album"
    : "All Media"

  const handleCopy = (url: string) => {
    navigator.clipboard.writeText(url)
    setCopiedUrl(url)
    setTimeout(() => setCopiedUrl(null), 2000)
  }

  const handleMoveClick = (item: MediaItem) => {
    setMovingItemId(item.id)
    setTargetAlbumId(item.albumId || "none")
    setIsMoveDialogOpen(true)
  }

  return (
    <div style={{ display: "grid", gridTemplateColumns: "240px 1fr", gap: "2rem", minHeight: "calc(100vh - 100px)" }}>

      {/* Sidebar */}
      <aside style={{ display: "flex", flexDirection: "column", gap: "1.5rem" }}>
        <div>
          <h3 style={{ fontSize: "0.75rem", fontWeight: "600", color: "#64748b", textTransform: "uppercase", letterSpacing: "0.05em", marginBottom: "0.75rem" }}>
            Library
          </h3>
          <div style={{ display: "flex", flexDirection: "column", gap: "0.25rem" }}>
            <button
              onClick={() => setSelectedAlbumId(null)}
              style={{
                display: "flex", alignItems: "center", gap: "0.75rem",
                padding: "0.625rem 0.875rem", borderRadius: "0.5rem",
                background: selectedAlbumId === null ? "#eff6ff" : "transparent",
                color: selectedAlbumId === null ? "#1d4ed8" : "#475569",
                border: "none", cursor: "pointer", fontSize: "0.875rem", fontWeight: "500",
                width: "100%", textAlign: "left"
              }}
            >
              <Grid style={{ width: "18px", height: "18px" }} />
              All Assets
            </button>
          </div>
        </div>

        <div>
           <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "0.75rem" }}>
              <h3 style={{ fontSize: "0.75rem", fontWeight: "600", color: "#64748b", textTransform: "uppercase", letterSpacing: "0.05em", margin: 0 }}>
                Albums
              </h3>
              <Dialog open={isCreateAlbumOpen} onOpenChange={setIsCreateAlbumOpen}>
                <DialogTrigger asChild>
                  <button style={{ background: "none", border: "none", color: "#3b82f6", cursor: "pointer" }}>
                    <Plus style={{ width: "16px", height: "16px" }} />
                  </button>
                </DialogTrigger>
                <DialogContent>
                  <DialogHeader>
                    <DialogTitle>Create New Album</DialogTitle>
                  </DialogHeader>
                  <div style={{ padding: "1rem 0" }}>
                    <Label htmlFor="album-name">Album Name</Label>
                    <Input 
                      id="album-name" 
                      value={newAlbumName} 
                      onChange={(e) => setNewAlbumName(e.target.value)}
                      placeholder="e.g. Portfolio Projects" 
                    />
                  </div>
                  <DialogFooter>
                    <Button variant="outline" onClick={() => setIsCreateAlbumOpen(false)}>Cancel</Button>
                    <Button onClick={() => createAlbumMutation.mutate(newAlbumName)} disabled={!newAlbumName || createAlbumMutation.isPending}>
                      Create Album
                    </Button>
                  </DialogFooter>
                </DialogContent>
              </Dialog>
           </div>

           <div style={{ display: "flex", flexDirection: "column", gap: "0.25rem" }}>
            {isAlbumsLoading ? (
               <p style={{ fontSize: "0.75rem", color: "#94a3b8", padding: "0 0.875rem" }}>Loading albums...</p>
            ) : albums?.map(album => (
              <button
                key={album.id}
                onClick={() => setSelectedAlbumId(album.id)}
                style={{
                  display: "flex", alignItems: "center", justifyContent: "space-between",
                  padding: "0.625rem 0.875rem", borderRadius: "0.5rem",
                  background: selectedAlbumId === album.id ? "#eff6ff" : "transparent",
                  color: selectedAlbumId === album.id ? "#1d4ed8" : "#475569",
                  border: "none", cursor: "pointer", fontSize: "0.875rem", fontWeight: "500",
                  width: "100%", textAlign: "left"
                }}
              >
                <div style={{ display: "flex", alignItems: "center", gap: "0.75rem", flex: 1 }}>
                  <Folder style={{ width: "18px", height: "18px", color: selectedAlbumId === album.id ? "#3b82f6" : "#94a3b8" }} />
                  {album.name}
                </div>
                <span style={{ fontSize: "0.75rem", opacity: 0.6 }}>{album.mediaCount}</span>
              </button>
            ))}
           </div>
        </div>
      </aside>

      {/* Main Content */}
      <main>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "1.5rem" }}>
          <div>
            <div style={{ display: "flex", alignItems: "center", gap: "0.5rem", color: "#64748b", fontSize: "0.875rem", marginBottom: "0.25rem" }}>
              <span>Media Library</span>
              <ChevronRight style={{ width: "14px", height: "14px" }} />
              <span style={{ color: "#0f172a", fontWeight: "600" }}>{currentAlbumName}</span>
            </div>
          </div>
          <UploadButton
            endpoint="imageUploader"
            onClientUploadComplete={(res) => {
              // If we are in an album, we might want to automatically tag the upload (Phase 4 improvement)
              queryClient.invalidateQueries({ queryKey: ["media-items"] })
              queryClient.invalidateQueries({ queryKey: ["media-albums"] })
              toast({ title: "Upload Complete", description: "New media added to library" })
            }}
            onUploadError={(error: Error) => {
              toast({ variant: "destructive", title: "Upload Failed", description: error.message })
            }}
            appearance={{
              button: {
                background: "#3b82f6", color: "white", fontSize: "0.875rem",
                fontWeight: "600", borderRadius: "0.5rem", padding: "0.625rem 1.25rem",
                height: "auto", width: "auto"
              },
              allowedContent: { display: "none" }
            }}
          />
        </div>

        <div style={{ background: "white", border: "1px solid #e2e8f0", borderRadius: "0.75rem", padding: "1rem", marginBottom: "1.5rem" }}>
          <div style={{ display: "flex", gap: "1rem", alignItems: "center" }}>
            <div style={{ position: "relative", flex: 1 }}>
              <Search style={{ position: "absolute", left: "12px", top: "50%", transform: "translateY(-50%)", width: "16px", height: "16px", color: "#94a3b8" }} />
              <input 
                type="text" 
                placeholder="Search by filename or type..." 
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                style={{ 
                  width: "100%", padding: "0.625rem 1rem 0.625rem 2.5rem", 
                  borderRadius: "0.5rem", border: "1px solid #e2e8f0", 
                  fontSize: "0.875rem", outline: "none"
                }}
              />
            </div>
          </div>
        </div>

        {isMediaLoading ? (
          <div style={{ padding: "4rem", textAlign: "center", color: "#94a3b8" }}>
             <p>Loading your masterpiece assets...</p>
          </div>
        ) : filteredMedia?.length === 0 ? (
          <div style={{ padding: "4rem", textAlign: "center", background: "#f8fafc", borderRadius: "0.75rem", border: "1px dashed #e2e8f0" }}>
             <FolderOpen style={{ width: "48px", height: "48px", color: "#cbd5e1", marginBottom: "1rem" }} />
             <p style={{ color: "#64748b", margin: 0 }}>No files in this view.</p>
          </div>
        ) : (
          <div style={{ 
            display: "grid", 
            gridTemplateColumns: "repeat(auto-fill, minmax(220px, 1fr))", 
            gap: "1.5rem" 
          }}>
            {filteredMedia?.map((item) => (
              <div key={item.id} className="group" style={{ 
                background: "white", borderRadius: "12px", 
                border: "1px solid #e2e8f0", overflow: "hidden",
                position: "relative", transition: "all 0.2s ease"
              }}>
                <div style={{ 
                  aspectRatio: "1/1", background: "#f8fafc", 
                  display: "flex", alignItems: "center", justifyContent: "center",
                  overflow: "hidden", position: "relative"
                }}>
                  {item.url.startsWith("http") ? (
                    <img 
                      src={item.url} 
                      alt={item.title} 
                      style={{ width: "100%", height: "100%", objectFit: "cover" }} 
                    />
                  ) : (
                    <ImageIcon style={{ width: "40px", height: "40px", color: "#cbd5e1" }} />
                  )}

                  {/* Overlay Actions */}
                  <div style={{
                    position: "absolute", inset: 0, background: "rgba(15, 23, 42, 0.4)",
                    display: "flex", alignItems: "center", justifyContent: "center", gap: "0.5rem",
                    opacity: 0, transition: "opacity 0.2s", backdropFilter: "blur(2px)"
                  }} className="hover-overlay">
                    <button 
                      onClick={() => handleCopy(item.url)}
                      style={{ padding: "0.5rem", background: "white", borderRadius: "0.5rem", border: "none", cursor: "pointer" }}
                      title="Copy Link"
                    >
                      {copiedUrl === item.url ? <Check style={{ width: "16px", height: "16px", color: "#10b981" }} /> : <Copy style={{ width: "16px", height: "16px" }} />}
                    </button>
                    <button 
                      onClick={() => handleMoveClick(item)}
                      style={{ padding: "0.5rem", background: "white", borderRadius: "0.5rem", border: "none", cursor: "pointer" }}
                      title="Move to Album"
                    >
                      <Folder style={{ width: "16px", height: "16px", color: "#3b82f6" }} />
                    </button>
                    <button 
                      onClick={() => { if(confirm("Are you sure?")) deleteMutation.mutate(item.id) }}
                      style={{ padding: "0.5rem", background: "white", borderRadius: "0.5rem", border: "none", cursor: "pointer" }}
                      title="Delete"
                    >
                      <Trash2 style={{ width: "16px", height: "16px", color: "#ef4444" }} />
                    </button>
                  </div>
                </div>

                <div style={{ padding: "0.875rem" }}>
                  <p style={{ 
                    fontSize: "0.875rem", fontWeight: "600", color: "#0f172a", 
                    margin: "0 0 0.25rem", whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" 
                  }}>
                    {item.title || "Untitled"}
                  </p>
                  <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
                    <span style={{ fontSize: "0.75rem", color: "#94a3b8", textTransform: "capitalize" }}>
                      {item.type.includes('/') ? item.type.split('/')[1] : item.type}
                    </span>
                    <button 
                      onClick={() => window.open(item.url, "_blank")}
                      style={{ background: "none", border: "none", color: "#94a3b8", cursor: "pointer" }}
                    >
                      <ExternalLink style={{ width: "14px", height: "14px" }} />
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </main>

      {/* Move Dialog */}
      <Dialog open={isMoveDialogOpen} onOpenChange={setIsMoveDialogOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Move to Album</DialogTitle>
          </DialogHeader>
          <div style={{ padding: "1rem 0" }}>
            <Label>Target Album</Label>
            <Select value={targetAlbumId} onValueChange={setTargetAlbumId}>
              <SelectTrigger>
                <SelectValue placeholder="Select an album" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="none">No Album (Unorganized)</SelectItem>
                {albums?.map(a => (
                  <SelectItem key={a.id} value={a.id}>{a.name}</SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setIsMoveDialogOpen(false)}>Cancel</Button>
            <Button 
              onClick={() => moveMutation.mutate({ 
                id: movingItemId!, 
                albumId: targetAlbumId === "none" ? null : targetAlbumId 
              })}
              disabled={moveMutation.isPending}
            >
              Move File
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Basic HOVER CSS */}
      <style jsx global>{`
        .group:hover .hover-overlay {
          opacity: 1 !important;
        }
      `}</style>
    </div>
  )
}

