import { NextRequest } from "next/server"
import { db } from "@/db"
import { activityLogs, users } from "@/db/schema"
import { desc, eq, sql } from "drizzle-orm"
import { requireRole } from "@/lib/auth-helpers"

export async function GET(request: NextRequest) {
  // Only super_admin and editor can view audit logs
  const session = await requireRole(request, ["super_admin", "editor"])
  if (!session) return Response.json({ error: "Unauthorized" }, { status: 401 })

  const { searchParams } = new URL(request.url)
  const limit = parseInt(searchParams.get("limit") || "50")
  const offset = parseInt(searchParams.get("offset") || "0")

  try {
    const logs = await db
      .select({
        id: activityLogs.id,
        action: activityLogs.action,
        resourceType: activityLogs.resourceType,
        resourceId: activityLogs.resourceId,
        metadata: activityLogs.metadata,
        ipAddress: activityLogs.ipAddress,
        createdAt: activityLogs.createdAt,
        user: {
          name: users.name,
          email: users.email,
        }
      })
      .from(activityLogs)
      .leftJoin(users, eq(activityLogs.userId, users.id))
      .orderBy(desc(activityLogs.createdAt))
      .limit(limit)
      .offset(offset)

    return Response.json(logs)
  } catch (error) {
    console.error("Failed to fetch activity logs:", error)
    return Response.json({ error: "Failed to fetch logs" }, { status: 500 })
  }
}

import { NextRequest } from "next/server"
export const dynamic = "force-dynamic"
import { db } from "@/db"
import { articles, categories, users } from "@/db/schema"
import { eq, desc, like, and, sql, ilike } from "drizzle-orm"
import { requireAuth } from "@/lib/auth-helpers"
import { logActivity } from "@/lib/activity-logger"
import {
  articleQuerySchema,
  createArticleSchema,
} from "@/lib/validations/articles"
import { slugify, sanitize, computeReadingTime } from "@/lib/utils"

export async function GET(request: NextRequest) {
  const session = await requireAuth(request)
  if (!session) return Response.json({ error: "Unauthorized" }, { status: 401 })

  const { searchParams } = new URL(request.url)
  const query = articleQuerySchema.parse({
    page: searchParams.get("page") ?? "1",
    limit: searchParams.get("limit") ?? "20",
    status: searchParams.get("status") ?? undefined,
    category: searchParams.get("category") ?? undefined,
    search: searchParams.get("search") ?? undefined,
  })

  const offset = (query.page - 1) * query.limit

  const conditions = [
    query.status ? eq(articles.status, query.status) : undefined,
    query.category ? eq(articles.categoryId, query.category) : undefined,
    query.search ? ilike(articles.title, `%${query.search}%`) : undefined,
  ].filter(Boolean) as ReturnType<typeof eq>[]

  const [data, [totalRow]] = await Promise.all([
    db
      .select({
        id: articles.id,
        title: articles.title,
        slug: articles.slug,
        status: articles.status,
        excerpt: articles.excerpt,
        coverImage: articles.coverImage,
        tags: articles.tags,
        readingTime: articles.readingTime,
        createdAt: articles.createdAt,
        updatedAt: articles.updatedAt,
        publishedAt: articles.publishedAt,
        author: {
          id: users.id,
          name: users.name,
          email: users.email,
        },
        category: {
          id: categories.id,
          name: categories.name,
        },
      })
      .from(articles)
      .leftJoin(users, eq(articles.authorId, users.id))
      .leftJoin(categories, eq(articles.categoryId, categories.id))
      .where(conditions.length > 0 ? and(...conditions) : undefined)
      .orderBy(desc(articles.updatedAt))
      .limit(query.limit)
      .offset(offset),

    db
      .select({ count: sql<number>`count(*)::int` })
      .from(articles)
      .where(conditions.length > 0 ? and(...conditions) : undefined),
  ])

  return Response.json({
    data,
    pagination: {
      page: query.page,
      limit: query.limit,
      total: totalRow.count,
      totalPages: Math.ceil(totalRow.count / query.limit),
    },
  })
}

export async function POST(request: NextRequest) {
  const session = await requireAuth(request)
  if (!session) return Response.json({ error: "Unauthorized" }, { status: 401 })

  const body = await request.json()
  const parsed = createArticleSchema.safeParse(body)
  if (!parsed.success) {
    return Response.json({ error: parsed.error.flatten() }, { status: 422 })
  }

  const slug = parsed.data.slug || slugify(parsed.data.title)

  const rawHtml = parsed.data.contentHtml ? sanitize(parsed.data.contentHtml) : ""
  // Strip the first H1 tag if it exists (usually the title duplicated from markdown)
  const sanitizedHtml = rawHtml.replace(/<h1[^>]*>[\s\S]*?<\/h1>/i, "").trim()
  const readingTime = computeReadingTime(sanitizedHtml)

  const [article] = await db
    .insert(articles)
    .values({
      title: parsed.data.title,
      slug,
      content: parsed.data.content as Record<string, unknown>,
      contentHtml: sanitizedHtml,
      excerpt: parsed.data.excerpt,
      status: parsed.data.status,
      categoryId: parsed.data.categoryId,
      authorId: session.user.id,
      coverImage: parsed.data.coverImage || null,
      tags: parsed.data.tags,
      readingTime,
      publishedAt:
        parsed.data.status === "published" ? new Date() : undefined,
    })
    .returning()

  logActivity({
    userId: session.user.id,
    action: "article.create",
    resourceId: article.id,
    resourceType: "article",
    metadata: { title: article.title, status: article.status },
  })

  return Response.json({ data: article }, { status: 201 })
}

import { NextRequest } from "next/server"
import { db } from "@/db"
import { articles, emails, users, activityLogs } from "@/db/schema"
import { desc, sql, eq, gte, and, lt } from "drizzle-orm"
import { requireAuth } from "@/lib/auth-helpers"

export async function GET(request: NextRequest) {
  const session = await requireAuth(request)
  if (!session) return Response.json({ error: "Unauthorized" }, { status: 401 })

  const thirtyDaysAgo = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000)

  const [articleStats, emailStats, userStats, recentActivity] = await Promise.all([
    db
      .select({
        status: articles.status,
        count: sql<number>`count(*)::int`,
      })
      .from(articles)
      .groupBy(articles.status),

    db
      .select({ 
        status: emails.status,
        count: sql<number>`count(*)::int` 
      })
      .from(emails)
      .groupBy(emails.status),

    db.select({ count: sql<number>`count(*)::int` }).from(users),

    db
      .select()
      .from(activityLogs)
      .orderBy(desc(activityLogs.createdAt))
      .limit(15),
  ])

  const totalArticles = articleStats.reduce((s, r) => s + r.count, 0)
  const publishedArticles =
    articleStats.find((r) => r.status === "published")?.count ?? 0
  const draftArticles =
    articleStats.find((r) => r.status === "draft")?.count ?? 0

  // 7-day activity breakdown (Optimized)
  const sevenDaysAgo = new Date()
  sevenDaysAgo.setDate(sevenDaysAgo.getDate() - 6)
  sevenDaysAgo.setHours(0, 0, 0, 0)

  const [articlesByDay, emailsByDay] = await Promise.all([
    db
      .select({
        date: sql<string>`DATE_TRUNC('day', ${articles.createdAt})`,
        count: sql<number>`count(*)::int`,
      })
      .from(articles)
      .where(gte(articles.createdAt, sevenDaysAgo))
      .groupBy(sql`DATE_TRUNC('day', ${articles.createdAt})`),
    db
      .select({
        date: sql<string>`DATE_TRUNC('day', ${emails.createdAt})`,
        count: sql<number>`count(*)::int`,
      })
      .from(emails)
      .where(gte(emails.createdAt, sevenDaysAgo))
      .groupBy(sql`DATE_TRUNC('day', ${emails.createdAt})`),
  ])

  const activityData = Array.from({ length: 7 }).map((_, i) => {
    const date = new Date()
    date.setDate(date.getDate() - (6 - i))
    date.setHours(0, 0, 0, 0)

    // Find count for this specific day (handle potential timezone/format differences)
    const articleCount = articlesByDay.find(d => 
      new Date(d.date).toDateString() === date.toDateString()
    )?.count ?? 0

    const emailCount = emailsByDay.find(d => 
      new Date(d.date).toDateString() === date.toDateString()
    )?.count ?? 0

    return {
      name: date.toLocaleDateString("en-US", { weekday: "short" }),
      articles: articleCount,
      emails: emailCount,
    }
  })

  const totalReceived = emailStats.find(s => s.status === "received")?.count ?? 0
  const totalSent = emailStats.find(s => s.status === "sent")?.count ?? 0
  const totalFailed = emailStats.find(s => s.status === "failed")?.count ?? 0

  return Response.json({
    articles: {
      total: totalArticles,
      published: publishedArticles,
      draft: draftArticles,
    },
    emails: { 
      total: totalReceived,
      sent: totalSent,
      failed: totalFailed
    },
    users: { total: userStats[0]?.count ?? 0 },
    recentActivity,
    activityData,
    since: thirtyDaysAgo,
  })
}

import { NextRequest } from "next/server"
import { db } from "@/db"
import { emailCampaigns, emailRecipients } from "@/db/schema"
import { eq, desc } from "drizzle-orm"
import { requireAuth } from "@/lib/auth-helpers"

export async function GET(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  const session = await requireAuth(request)
  if (!session) return Response.json({ error: "Unauthorized" }, { status: 401 })

  const { id } = await params
  const campaign = await db.query.emailCampaigns.findFirst({
    where: eq(emailCampaigns.id, id),
    with: {
      template: true,
      sender: true,
      recipients: {
        orderBy: [desc(emailRecipients.createdAt)],
      },
    },
  })

  if (!campaign) {
    return Response.json({ error: "Campaign not found" }, { status: 404 })
  }

  return Response.json({ data: campaign })
}

export async function PATCH(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  const session = await requireAuth(request)
  if (!session) return Response.json({ error: "Unauthorized" }, { status: 401 })

  try {
    const { id } = await params
    const body = await request.json()
    // Supported actions: cancel, retry_failed
    if (body.action === "cancel") {
      await db.update(emailCampaigns).set({ status: "cancelled" }).where(eq(emailCampaigns.id, id))
    } else if (body.action === "retry_failed") {
      await db.update(emailRecipients).set({ status: "pending", error: null }).where(eq(emailRecipients.campaignId, id))
      await db.update(emailCampaigns).set({ status: "processing" }).where(eq(emailCampaigns.id, id))
    }

    return Response.json({ success: true })
  } catch (error) {
    return Response.json({ error: "Internal Server Error" }, { status: 500 })
  }
}

export async function DELETE(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  const session = await requireAuth(request)
  if (!session) return Response.json({ error: "Unauthorized" }, { status: 401 })

  try {
    const { id } = await params
    await db.delete(emailCampaigns).where(eq(emailCampaigns.id, id))
    return Response.json({ success: true })
  } catch (error) {
    return Response.json({ error: "Internal Server Error" }, { status: 500 })
  }
}

import { NextRequest } from "next/server"
import { db } from "@/db"
import { emailCampaigns, emailRecipients } from "@/db/schema"
import { requireAuth } from "@/lib/auth-helpers"
import { campaignCreationLimit } from "@/lib/ratelimit"
import * as z from "zod"

const campaignSchema = z.object({
  name: z.string().min(1, "Name is required"),
  subject: z.string().min(1, "Subject is required"),
  templateId: z.string().uuid().optional(),
  senderId: z.string().uuid(),
  bodyHtml: z.string().min(1, "Body is required"),
  scheduledAt: z.string().optional(), // Expected as date string
  recipients: z.array(z.string().email("Invalid email address")).min(1, "At least one recipient is required"),
})

export async function POST(request: NextRequest) {
  const session = await requireAuth(request)
  if (!session) return Response.json({ error: "Unauthorized" }, { status: 401 })

  try {
    // Rate limit — inside try/catch so Redis failures are handled gracefully
    const { success } = await campaignCreationLimit.limit(session.user.id)
    if (!success) {
      return Response.json({ error: "Too many campaigns created. Please wait an hour." }, { status: 429 })
    }

    const json = await request.json()
    const body = campaignSchema.parse(json)

    // Start a transaction
    const result = await db.transaction(async (tx) => {
      // 1. Create the campaign
      const [newCampaign] = await tx
        .insert(emailCampaigns)
        .values({
          name: body.name,
          subject: body.subject,
          templateId: body.templateId,
          senderId: body.senderId,
          bodyHtml: body.bodyHtml,
          scheduledAt: body.scheduledAt ? new Date(body.scheduledAt) : null,
          status: body.scheduledAt ? "scheduled" : "pending",
          totalRecipients: body.recipients.length,
          createdById: session.user.id,
        })
        .returning()

      // 2. Add recipients
      const recipientData = body.recipients.map((email) => ({
        campaignId: newCampaign.id,
        email,
        status: "pending" as any,
      }))

      // Batch insert recipients for efficiency
      // Drizzle handles multiple values in insert
      if (recipientData.length > 0) {
        await tx.insert(emailRecipients).values(recipientData)
      }

      return newCampaign
    })

    return Response.json({ data: result })
  } catch (error) {
    console.error("Campaign Creation Error:", error instanceof Error ? error.message : error)
    if (error instanceof z.ZodError) {
      return Response.json({ error: error.issues }, { status: 400 })
    }
    const message = error instanceof Error ? error.message : "Internal Server Error"
    return Response.json({ error: message }, { status: 500 })
  }
}

export async function GET(request: NextRequest) {
  const session = await requireAuth(request)
  if (!session) return Response.json({ error: "Unauthorized" }, { status: 401 })

  const campaigns = await db.query.emailCampaigns.findMany({
    orderBy: (t, { desc }) => [desc(t.createdAt)],
    with: {
      template: true,
      sender: true,
    },
  })

  return Response.json({ data: campaigns })
}

