  if (!session) return NextResponse.json({ error: "Unauthorized" }, { status: 401 })

  try {
    const body = await request.json()
    const [newItem] = await db.insert(experiences).values({
      company: body.company,
      role: body.role,
      period: body.period,
      location: body.location,
      current: body.current ?? false,
      bullets: body.bullets ?? [],
      order: body.order ?? 0,
    }).returning()

    await logActivity({
      userId: session.user.id,
      action: "profile.experience.create",
      resourceId: newItem.id,
      resourceType: "experience",
      metadata: { company: newItem.company, role: newItem.role }
    })

    return NextResponse.json(newItem, { status: 201 })
  } catch (error) {
    console.error("POST experiences error:", error)
    return NextResponse.json({ error: "Failed to create experience" }, { status: 500 })
  }
}

import { NextRequest, NextResponse } from "next/server"
import { db } from "@/db"
import { siteSettings } from "@/db/schema"
import { eq } from "drizzle-orm"
import { requireRole } from "@/lib/auth-helpers"
import { logActivity } from "@/lib/activity-logger"

export async function GET(request: NextRequest) {
  try {
    const data = await db.query.siteSettings.findMany()
    // Return as a key-value object for easier consumption
    const settings = data.reduce((acc, curr) => {
      acc[curr.key] = curr.value
      return acc
    }, {} as Record<string, unknown>)

    return NextResponse.json(settings)
  } catch (error) {
    return NextResponse.json({ error: "Failed to fetch settings" }, { status: 500 })
  }
}

export async function PATCH(request: NextRequest) {
  const session = await requireRole(request, ["super_admin"])
  if (!session) return NextResponse.json({ error: "Unauthorized" }, { status: 401 })

  try {
    const body = await request.json()
    const entries = Object.entries(body)

    const results = []
    for (const [key, value] of entries) {
      const [updated] = await db.insert(siteSettings)
        .values({ key, value })
        .onConflictDoUpdate({
          target: siteSettings.key,
          set: { value, updatedAt: new Date() }
        })
        .returning()
      results.push(updated)
    }

    await logActivity({
      userId: session.user.id,
      action: "profile.settings.update",
      metadata: { keys: Object.keys(body) }
    })

    return NextResponse.json({ success: true, count: results.length })
  } catch (error) {
    console.error("PATCH settings error:", error)
    return NextResponse.json({ error: "Failed to update settings" }, { status: 500 })
  }
}

import { NextRequest, NextResponse } from "next/server"
import { db } from "@/db"
import { skills } from "@/db/schema"
import { eq } from "drizzle-orm"
import { requireRole } from "@/lib/auth-helpers"
import { logActivity } from "@/lib/activity-logger"

export async function PATCH(request: NextRequest, { params }: { params: Promise<{ id: string }> }) {
  const { id } = await params
  const session = await requireRole(request, ["super_admin", "editor"])
  if (!session) return NextResponse.json({ error: "Unauthorized" }, { status: 401 })

  try {
    const body = await request.json()

    // Explicitly mapping allowed fields only
    const { name, level, category, order } = body

    const [updated] = await db.update(skills)
      .set({
        name,
        level,
        category,
        order,
      })
      .where(eq(skills.id, id))
      .returning()

    if (!updated) return NextResponse.json({ error: "Not found" }, { status: 404 })

    await logActivity({
      userId: session.user.id,
      action: "profile.skill.update",
      resourceId: updated.id,
      resourceType: "skill",
      metadata: { name: updated.name, ...body }
    })

    return NextResponse.json(updated)
  } catch (error) {
    return NextResponse.json({ error: "Failed to update skill" }, { status: 500 })
  }
}

export async function DELETE(request: NextRequest, { params }: { params: Promise<{ id: string }> }) {
  const { id } = await params
  const session = await requireRole(request, ["super_admin", "editor"])
  if (!session) return NextResponse.json({ error: "Unauthorized" }, { status: 401 })

  try {
    const [deleted] = await db.delete(skills)
      .where(eq(skills.id, id))
      .returning()

    if (!deleted) return NextResponse.json({ error: "Not found" }, { status: 404 })

    await logActivity({
      userId: session.user.id,
      action: "profile.skill.delete",
      resourceId: id,
      resourceType: "skill",
      metadata: { name: deleted.name }
    })

    return NextResponse.json({ success: true })
  } catch (error) {
    return NextResponse.json({ error: "Failed to delete skill" }, { status: 500 })
  }
}

